fibonacci:
# Proc to calculate the Nth Fibonacci number iteratively
proc fibonacci {n} {
    if {$n < 0} {error "Input must be non-negative"}
    if {$n == 0} {return 0}

    set a 0
    set b 1

    for {set i 2} {$i <= $n} {incr i} {
        set temp [expr {$a + $b}]
        set a $b
        set b $temp
    }
    return $b
}

set num_terms 15
puts "First $num_terms Fibonacci numbers:"
for {set i 0} {$i < $num_terms} {incr i} {
    puts -nonewline "[fibonacci $i] "
}
puts ""

# Tcl handles arbitrary-precision integers automatically
puts "F(90) = [fibonacci 90]"

factorial:
# Proc to calculate factorial N! iteratively
proc factorial {n} {
    if {$n < 0} {error "Factorial is not defined for negative numbers"}
    set result 1
    for {set i 2} {$i <= $n} {incr i} {
        set result [expr {$result * $i}]
    }
    return $result
}

puts "Factorial of 5 is [factorial 5]"
puts "Factorial of 0 is [factorial 0]"

# Tcl handles arbitrary-precision integers automatically
puts "Factorial of 30 is [factorial 30]"

primeCheck:
# Proc to check if a number is prime
proc is_prime {n} {
    if {$n <= 1} {return false}
    if {$n <= 3} {return true}
    if {[expr {$n % 2 == 0 || $n % 3 == 0}]} {return false}

    set limit [expr {int(sqrt($n))}]
    for {set i 5} {$i <= $limit} {incr i 6} {
        if {[expr {$n % $i == 0 || $n % ($i + 2) == 0}]} {
            return false
        }
    }
    return true
}

foreach num {2 3 4 17 25 29 97 104729} {
    if {[is_prime $num]} {
        puts "$num is prime."
    } else {
        puts "$num is not prime."
    }
}

readFile:
set filename "tcl_read_test.txt"

# Create a dummy file for reading
if {[catch {set chan [open $filename w]} msg]} {
    puts stderr "Error creating file: $msg"
} else {
    puts $chan "First line from Tcl."
    puts $chan "Second line."
    close $chan
    puts "Created dummy file: $filename"
}

puts "\n--- Reading file '$filename' ---"
if {[catch {set chan [open $filename r]} msg]} {
    puts stderr "Error opening file: $msg"
} else {
    # Read line by line
    while {[gets $chan line] >= 0} {
        puts "Read line: $line"
    }
    close $chan
}

writeFile:
set filename "output_tcl.txt"

# 1. Overwrite or create a new file
puts "--- Writing (Overwrite) to '$filename' ---"
if {[catch {set chan [open $filename w]} msg]} {
    puts stderr "Error writing to file: $msg"
} else {
    puts $chan "This line overwrites existing content."
    puts $chan "Written from a Tcl script."
    close $chan
    puts "Content written successfully."
}

# 2. Append to the existing file
puts "\n--- Appending to '$filename' ---"
if {[catch {set chan [open $filename a]} msg]} {
    puts stderr "Error appending to file: $msg"
} else {
    puts $chan "This line was appended."
    close $chan
    puts "Content appended successfully."
}

maxInArray:
# Tcl uses lists. Find the max value in a list.

set numbers {10 5 42 17 8 99 32 -5 0}
puts "List: $numbers"

# Use 'lsort' to sort numerically and get the last element
if {[llength $numbers] > 0} {
    set sorted_numbers [lsort -real $numbers]
    set max_value [lindex $sorted_numbers end]
    puts "Maximum value: $max_value"
} else {
    puts "The list is empty."
}

# Example with an empty list
set empty_list {}
puts "\nList: $empty_list"
if {[llength $empty_list] > 0} {
    set max_value [lindex [lsort -real $empty_list] end]
    puts "Maximum value: $max_value"
} else {
    puts "The list is empty."
}
